            Console.WriteLine($"  Method: {m.Name} -> {m.ReturnType}");
            foreach (var gp in m.GetGenericArguments()) {
                Console.WriteLine($"    GenParam: {gp.Name}");
                foreach (var c in gp.GetGenericParameterConstraints()) {
                    Console.WriteLine($"      Constraint: {c.FullName ?? c.Name}");
                }
                Console.WriteLine($"      Attrs: {gp.GenericParameterAttributes}");
            }
        }
    }
}
